def sentence_count(value):
    return len(re.findall(r"[.!?](?:\s|$)", value.strip()))


def main():
    overrides = json.loads(OVERRIDES_PATH.read_text(encoding="utf-8"))
    missing = sorted(set(DESCRIPTIONS) - set(overrides))
    if missing:
        raise SystemExit(f"Missing product overrides: {', '.join(missing)}")

    for product_id, description in DESCRIPTIONS.items():
        count = sentence_count(description)
        if count < 2 or count > 4:
            raise SystemExit(f"{product_id}: expected 2-4 sentences, got {count}")
        if len(description) < 150 or len(description) > 430:
            raise SystemExit(f"{product_id}: suspicious description length {len(description)}")
        overrides[product_id]["description"] = description

    OVERRIDES_PATH.write_text(
        json.dumps(overrides, ensure_ascii=False, indent=2) + "\n",
        encoding="utf-8",
    )
    print(f"Updated {len(DESCRIPTIONS)} product descriptions")


if __name__ == "__main__":
    main()
